  1	import React, { FC } from 'react';
  2	import { Controller, FieldArrayWithId, useFieldArray, useFormContext } from 'react-hook-form';
  3	
  4	import { IoK8sApiCoreV1Service } from '@kubevirt-ui/kubevirt-api/kubernetes/models';
  5	import { ResourceIcon } from '@openshift-console/dynamic-plugin-sdk';
  6	import {
  7	  Button,
  8	  DropdownItem,
  9	  FormGroup,
 10	  FormHelperText,
 11	  HelperText,
 12	  HelperTextItem,
 13	  TextInput,
 14	} from '@patternfly/react-core';
 15	import { MinusCircleIcon } from '@patternfly/react-icons';
 16	import Select from '@utils/components/Select/Select';
 17	import { useNetworkingTranslation } from '@utils/hooks/useNetworkingTranslation';
 18	import { getName } from '@utils/resources/shared';
 19	import { RouteKind } from '@utils/types';
 20	
 21	import {
 22	  AS_PREFIX_FIELD_ID,
 23	  AS_WEIGHT_PREFIX_FIELD_ID,
 24	  ServiceGroupVersionKind,
 25	} from './constants';
 26	
 27	type AlternateServiceProps = {
 28	  field: FieldArrayWithId<RouteKind, 'spec.alternateBackends', 'id'>;
 29	  filteredServices: IoK8sApiCoreV1Service[];
 30	  index: number;
 31	};
 32	
 33	const AlternateService: FC<AlternateServiceProps> = ({ field, filteredServices, index }) => {
 34	  const { t } = useNetworkingTranslation();
 35	
 36	  const { control, register } = useFormContext<RouteKind>();
 37	
 38	  const { remove } = useFieldArray({ control, name: 'spec.alternateBackends' });
 39	
 40	  return (
 41	    <Controller
 42	      control={control}
 43	      key={field.id}
 44	      name={`spec.alternateBackends.${index}.name`}
 45	      render={({ field: { onChange, value } }) => (
 46	        <>
 47	          <div className="co-add-remove-form__link--remove-entry">
 48	            <Button isInline onClick={() => remove(index)} type="button" variant="link">
 49	              <MinusCircleIcon className="co-icon-space-r" />
 50	              {t('Remove alternate Service')}
 51	            </Button>
 52	          </div>
 53	          <FormGroup
 54	            fieldId={`${AS_PREFIX_FIELD_ID}${field.id}`}
 55	            isRequired
 56	            label={t('Alternate Service target')}
 57	          >
 58	            <Select
 59	              id={`${AS_PREFIX_FIELD_ID}${field.id}`}
 60	              selected={value}
 61	              toggleContent={
 62	                value ? (
 63	                  <>
 64	                    <ResourceIcon groupVersionKind={ServiceGroupVersionKind} /> {value}
 65	                  </>
 66	                ) : (
 67	                  t('Select a Service')
 68	                )
 69	              }
 70	            >
 71	              <>
 72	                {filteredServices.map((service) => (
 73	                  <DropdownItem
 74	                    key={getName(service)}
 75	                    onClick={() => onChange(getName(service))}
 76	                    value={getName(service)}
 77	                  >
 78	                    <ResourceIcon groupVersionKind={ServiceGroupVersionKind} /> {getName(service)}
 79	                  </DropdownItem>
 80	                ))}
 81	              </>
 82	            </Select>
 83	
 84	            <FormHelperText>
 85	              <HelperText>
 86	                <HelperTextItem>{t('Alternate Service to route to.')}</HelperTextItem>
 87	              </HelperText>
 88	            </FormHelperText>
 89	          </FormGroup>
 90	          <FormGroup
 91	            fieldId={`${AS_WEIGHT_PREFIX_FIELD_ID}${field.id}`}
 92	            isRequired
 93	            label={t('Alternate Service weight')}
 94	          >
 95	            <TextInput
 96	              id={`${AS_WEIGHT_PREFIX_FIELD_ID}${field.id}`}
 97	              max={255}
 98	              min={0}
 99	              type="number"
100	              {...register(`spec.alternateBackends.${index}.weight` as const, {
101	                setValueAs: parseInt,
102	              })}
103	            />
104	            <FormHelperText>
105	              <HelperText>
106	                <HelperTextItem>
107	                  {t(
108	                    'A number between 0 and 255 that depicts relative weight compared with other targets.',
109	                  )}
110	                </HelperTextItem>
111	              </HelperText>
112	            </FormHelperText>
113	          </FormGroup>
114	        </>
115	      )}
116	    ></Controller>
117	  );
118	};
119	
120	export default AlternateService;

